              ['Chennai Super Kings', '11-20', '35.5%', '2-3', 'CSK historically dominant; margin narrowing'],
              ['Lucknow Super Giants', '2-4', '33.3%', '2-2', 'Small sample; trending toward equilibrium'],
              ['Gujarat Titans', '1-3', '25.0%', '1-2', 'Varun\'s inability to take wickets vs GT is the concern']
